const STYLES = {
  base: {
    background: "rgba(15, 23, 42, 0.95)",
    color: "#f1f5f9",
    border: "1px solid rgba(255,255,255,0.1)",
    backdropFilter: "blur(16px)",
    WebkitBackdropFilter: "blur(16px)",
  },
  success: {
    borderLeft: "4px solid #10b981",
    icon: "✓",
    iconColor: "#10b981",
    iconBg: "rgba(16, 185, 129, 0.15)",
  },
  warning: {
    borderLeft: "4px solid #f59e0b",
    icon: "⚠",
    iconColor: "#f59e0b",
    iconBg: "rgba(245, 158, 11, 0.15)",
  },
  error: {
    borderLeft: "4px solid #ef4444",
    icon: "✕",
    iconColor: "#ef4444",
    iconBg: "rgba(239, 68, 68, 0.15)",
  },
  info: {
    borderLeft: "4px solid #4F46E5",
    icon: "ℹ",
    iconColor: "#4F46E5",
    iconBg: "rgba(79, 70, 229, 0.15)",
  },
};

function createToast({ message, type = "info", duration = 4000 }) {
  const toast = document.createElement("div");

  const style = {
    ...STYLES.base,
    ...(STYLES[type] || {}),
  };

  Object.assign(toast.style, {
    minWidth: "280px",
    maxWidth: "380px",
    padding: "14px 20px",
    borderRadius: "14px",
    boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
    fontFamily: "var(--font-sans, 'Outfit', system-ui, sans-serif)",
    fontSize: "14px",
    display: "flex",
    alignItems: "center",
    gap: "12px",
    transform: "translateX(120%) scale(0.9)",
    opacity: "0",
    transition: "all 0.4s cubic-bezier(0.16, 1, 0.3, 1)",
    cursor: "pointer",
    position: "relative",
    overflow: "hidden",
    ...style,
  });

  // Icon container
  const iconWrap = document.createElement("span");
  Object.assign(iconWrap.style, {
    width: "28px",
    height: "28px",
    borderRadius: "8px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "14px",
    fontWeight: "700",
    flexShrink: "0",
    background: style.iconBg || "rgba(255,255,255,0.1)",
    color: style.iconColor || "#94a3b8",
  });
  iconWrap.textContent = style.icon || "";

  // Message
  const text = document.createElement("span");
  text.textContent = message;
  Object.assign(text.style, {
    flex: "1",
    fontWeight: "500",
    letterSpacing: "0.01em",
    lineHeight: "1.4",
  });

  // Progress bar
  const progress = document.createElement("div");
  Object.assign(progress.style, {
    position: "absolute",
    bottom: "0",
    left: "0",
    height: "3px",
    width: "100%",
    background: style.iconColor || "#4F46E5",
    opacity: "0.6",
    borderRadius: "0 0 14px 14px",
    transition: `width ${duration}ms linear`,
  });

  toast.appendChild(iconWrap);
  toast.appendChild(text);
  toast.appendChild(progress);
  container.appendChild(toast);

  // Animate in
  requestAnimationFrame(() => {
    toast.style.transform = "translateX(0) scale(1)";
    toast.style.opacity = "1";
    // Start progress countdown
    requestAnimationFrame(() => {
      progress.style.width = "0%";
    });
  });

  const remove = () => {
    toast.style.transform = "translateX(120%) scale(0.9)";
    toast.style.opacity = "0";
    setTimeout(() => toast.remove(), 400);
  };

  const timeout = setTimeout(remove, duration);

  toast.addEventListener("click", () => {
    clearTimeout(timeout);
    remove();
  });
}

document.addEventListener("show-toast", (e) => {
  const { message, type, duration } = e.detail || {};
  if (!message) return;
  createToast({ message, type, duration });
});
